async analyzeSearchQuery({
	query,
}: {
	query: string;
}): Promise<IConversationAnalysisResponse> {
	const response = await this.openai.responses.create({
		model: 'gpt-4o-mini',
		instructions: this.buildConversationSystemPrompt(),
		input: `Analyze this search query and respond in json: ${query}`,
		store: true,
		text: { format: { type: 'json_object' } },
		temperature: 0.2,
		max_output_tokens: 190,
	});

	return {
		responseId: response.id,
		result: this.parseAnalysisResponse({ content: response.output_text }),
	};
}

@LogExecution({
	paramFormatter: (params: [{ previousResponseId: string; userMessage: string }]) => ({
		previousResponseId: params[0].previousResponseId,
	}),
})
async continueSearchAnalysis({
	previousResponseId,
	userMessage,
}: {
	previousResponseId: string;
	userMessage: string;
}): Promise<IConversationAnalysisResponse> {
	const response = await this.openai.responses.create({
		model: 'gpt-4o-mini',
		instructions: this.buildConversationSystemPrompt(),
		input: `Additional context from user, respond in json: ${userMessage}`,
		previous_response_id: previousResponseId,
		store: true,
		text: { format: { type: 'json_object' } },
		temperature: 0.2,
		max_output_tokens: 190,
	});

	return {
		responseId: response.id,
		result: this.parseAnalysisResponse({ content: response.output_text }),
	};
}
